SELECT COUNT(*) FROM (
    SELECT 1 FROM outbox_event
    WHERE status = 'NEW'
      AND created_at <= #{tSafe, typeHandler=com.dogancaglar.common.db.typehandler.InstantTypeHandler}
    LIMIT 10000
) sub

mapper.update:
UPDATE outbox_event
SET status = 'NEW',
claimed_at = NULL,
claimed_by = NULL,
updated_at = now() AT TIME ZONE 'UTC'
WHERE oeid = #{oeid}
AND created_at = #{createdAt, typeHandler=com.dogancaglar.common.db.typehandler.InstantTypeHandler}
AND claimed_by = #{workerId}
